func (e *escaper) escapeTemplateBody(c context, t *template.Template) (context, bool) {
	filter := func(e1 *escaper, c1 context) bool {
		if c1.state == stateError {

			return false
		}
		if !e1.called[t.Name()] {

			return true
		}

		return c.eq(c1)
	}

	e.output[t.Name()] = c
	return e.escapeListConditionally(c, t.Tree.Root, filter)
}
